firmware_template.source:
#include "crc_checksum.h"
uint8_t crc8(const uint8_t*d,size_t l){uint8_t c=0;for(size_t i=0;i<l;i++){c^=d[i];for(int j=0;j<8;j++)c=(c&0x80)?(c<<1)^0x31:(c<<1);}return c;}
uint16_t crc16(const uint8_t*d,size_t l){uint16_t c=0xFFFF;for(size_t i=0;i<l;i++){c^=d[i];for(int j=0;j<8;j++)c=(c&1)?(c>>1)^0xA001:(c>>1);}return c;}
uint32_t crc32(const uint8_t*d,size_t l){uint32_t c=0xFFFFFFFF;for(size_t i=0;i<l;i++){c^=d[i];for(int j=0;j<8;j++)c=(c&1)?(c>>1)^0xEDB88320:(c>>1);}return c^0xFFFFFFFF;}
